import React from 'react';
import { motion, useReducedMotion } from 'framer-motion';
import { MapPinned } from 'lucide-react';
import PageLayout from '../components/PageLayout';

const MapView: React.FC = () => {
	const reduceMotion = useReducedMotion() ?? false;

	return (
		<div className="min-h-screen bg-[#030303] text-[#F9F8F3]">
			<PageLayout className="min-h-screen" contentClassName="flex min-h-[calc(100vh-9rem)] max-w-7xl items-center justify-center">
				<section className="flex w-full items-center justify-center">
					<div className="glass-card relative w-full max-w-4xl overflow-hidden rounded-[3rem] px-8 py-16 text-center sm:px-14 sm:py-20">
						<div className="pointer-events-none absolute inset-0 bg-[radial-gradient(circle_at_top,rgba(179,163,105,0.15),transparent_42%),radial-gradient(circle_at_bottom_right,rgba(16,185,129,0.12),transparent_40%)]" />
						<div className="relative mx-auto flex max-w-2xl flex-col items-center">
							<motion.div
								animate={reduceMotion ? { opacity: 1, scale: 1 } : { opacity: [0.82, 1, 0.82], scale: [1, 1.04, 1] }}
								transition={reduceMotion ? { duration: 0.16 } : { duration: 3.2, repeat: Infinity, ease: 'easeInOut' }}
								className="mb-8 inline-flex rounded-[1.75rem] border border-[#B3A369]/20 bg-white/[0.04] p-5 text-[#B3A369] shadow-[0_0_0_1px_rgba(148,163,184,0.1),0_0_28px_rgba(179,163,105,0.14)]"
							>
								<MapPinned size={44} strokeWidth={1.7} aria-hidden="true" />
							</motion.div>

							<p className="section-eyebrow mb-4 text-white/44">
								Charlotte Interactive Map
							</p>
							<h1 className="mb-6 text-5xl font-serif italic leading-[0.95] text-[#B3A369] serif-glow sm:text-6xl md:text-[4.2rem]">
								The map experience is next.
							</h1>
							<p className="section-copy max-w-2xl sm:text-xl">
								Mapbox is not implemented yet, but this space is reserved for the live Charlotte discovery view, route context, and place-based planning tools.
							</p>
						</div>
					</div>
				</section>
			</PageLayout>
		</div>
	);
};

export default MapView;
